cd /workspace/repo && cat > /tmp/test_callable.py << 'EOF'
import flask

app = flask.Flask(__name__)

# Test: callable for provide_automatic_options
def should_provide_options(app, methods):
    """Return False to disable OPTIONS, True to enable."""
    # Disable OPTIONS for /no-options routes
    return "no-options" not in app.url_map._rules_by_endpoint.get("test_no_options", [])

# Create a view function
@app.route("/test", methods=["GET"])
def test_view():
    return "OK"

# Test the add_url_rule with a callable
def dynamic_options(app, methods):
    # Disable OPTIONS only when methods is exactly GET
    return methods != {"GET"}

try:
    app.add_url_rule("/dynamic", view_func=test_view, provide_automatic_options=dynamic_options)
    print("SUCCESS: Callable accepted for provide_automatic_options")
except Exception as e:
    print(f"ERROR: {type(e).__name__}: {e}")
EOF
